{"code": "import json

# Load the results from storage
lit_fiction_books = []
with open('/tmp/tmpk9twhm9_.json', 'r') as f:
    lit_fiction_books = json.load(f)

perfect_ratings = []
with open('/tmp/tmpk2c9y1f.json', 'r') as f:
    perfect_ratings_data = json.load(f)
    purchase_ids_with_5_star = {item['purchase_id'] for item in perfect_ratings_data}

print("Number of Literature & Fiction books:", len(lit_fiction_books))
print("Number of purchase_ids with perfect 5.0 rating:", len(purchase_ids_with_5_star))

# Map book_id to purchase_id by extracting the numeric part
# book_id: bookid_X -> purchase_id: purchaseid_X where X is the number
book_id_to_purchase_id = {}
for book in lit_fiction_books:
    book_id = book['book_id']  # e.g., bookid_1
    if book_id.startswith('bookid_'):
        num = book_id.split('_')[1]
        purchase_id = f'purchaseid_{num}'
        book_id_to_purchase_id[book_id] = purchase_id

# Find which books have perfect ratings
books_with_perfect_ratings = []
for book in lit_fiction_books:
    book_id = book['book_id']
    if book_id in book_id_to_purchase_id:
        purchase_id = book_id_to_purchase_id[book_id]
        if purchase_id in purchase_ids_with_5_star:
            # Get the rating info
            rating_info = None
            for rate in perfect_ratings_data:
                if rate['purchase_id'] == purchase_id:
                    rating_info = rate
                    break

            if rating_info:
                books_with_perfect_ratings.append({
                    'title': book['title'],
                    'book_id': book_id,
                    'categories': book['categories'],
                    'avg_rating': rating_info['avg_rating'],
                    'review_count': rating_info['review_count']
                })

print("\nBooks with perfect 5.0 ratings in Literature & Fiction:")
for i, book in enumerate(books_with_perfect_ratings, 1):
    print(f"{i}. {book['title']} (ID: {book['book_id']})")
    print(f"   Reviews: {book['review_count']}, Avg Rating: {book['avg_rating']}")
    print(f"   Categories: {book['categories']}")

print(f"\n__RESULT__:")
print(json.dumps({
    'total_books_with_perfect_rating': len(books_with_perfect_ratings),
    'books': books_with_perfect_ratings
}, indent=2))"}

