{"code": "import json
import os

# Check what variables are available
available_vars = [key for key in dir() if key.startswith('var_')]
print("Available variables:", available_vars)

# Get the stored results
lit_fiction_path = None
perfect_ratings_data = None

for key in available_vars:
    if 'query_db' in key and (':8' in key or '_8' in key):
        lit_fiction_path = eval(key)
    if 'query_db' in key and (':12' in key or '_12' in key):
        perfect_ratings_data = eval(key)

print("Found literature path:", lit_fiction_path is not None)
print("Found perfect ratings:", perfect_ratings_data is not None)

# Process data if available
if lit_fiction_path and perfect_ratings_data:
    # Load literature & fiction books
    lit_fiction_books = []
    with open(lit_fiction_path, 'r') as f:
        lit_fiction_books = json.load(f)

    print(f"Loaded {len(lit_fiction_books)} literature & fiction books")

    # Process perfect ratings into dict
    purchase_ratings = {}
    for item in perfect_ratings_data:
        purchase_ratings[item['purchase_id']] = item

    # Find matches - bookid_X corresponds to purchaseid_X
    matching_books = []
    for book in lit_fiction_books:
        book_id = book['book_id']
        if book_id.startswith('bookid_'):
            num = book_id.split('_')[1]
            purchase_id = f'purchaseid_{num}'

            if purchase_id in purchase_ratings:
                rating_info = purchase_ratings[purchase_id]
                matching_books.append({
                    'title': book['title'],
                    'book_id': book_id,
                    'avg_rating': float(rating_info['avg_rating']),
                    'review_count': int(rating_info['review_count']),
                    'categories': book['categories']
                })

    print(f"Found {len(matching_books)} matching books")

    # Prepare result
    result = {
        'total_books': len(matching_books),
        'books': matching_books
    }
else:
    result = {'error': 'Missing data', 'total_books': 0, 'books': []}

# Output must follow exact format
print('__RESULT__:')
print(json.dumps(result))"}

